#include <bits/stdc++.h>using namespace std; int main() {    int t;    cin >> t;    while (t--) {        int a, b, c, d;        cin >> a >> b >> c >> d;        if (b > d) {            cout << -1 << "\n";        }        else {            int cnt = 0;            if (b <= d) {                cnt += (d - b);                a += (d - b);                b = d;            }            if (a < c) {                cout << -1 << "\n";            }            else {                cnt += (a - c);                cout << cnt << "\n";            }        }    }    return 0;}